//-------------------------------------------------------------------------
// function name : f_OnLoad
// function desc : 화면로딩시 
//-------------------------------------------------------------------------
scwin.onpageload = function () {
  $c.gus.cfDisableObjects($p, [ed_txt_prdyr, ed_txt_vehclNo, ed_txt_drcrNo, ed_txt_degNm, ed_txt_degForm, acb_eqNrmCd, ed_txt_stdFleffcncy, acb_lux_bizTypCd, acb_lux_trfAdptCd, ed_txt_outBranch, ica_em_inspDt1, ica_em_inspDt2, acb_lux_degClsCd, ica_em_degDt, ica_em_firstRegDt, ica_em_chkDt, rd_useYn, ed_txt_rmk]);
  const codeOptions = [{
    grpCd: "JA060",
    compID: "acb_eqNrmCd,gr_results:ton"
  }, {
    grpCd: "JA010",
    compID: "acb_lux_cond_bizTypCd,acb_lux_bizTypCd"
  }, {
    grpCd: "JA080",
    compID: "acb_lux_trfAdptCd"
  }, {
    grpCd: "JA090",
    compID: "acb_lux_degClsCd"
  }];
  $c.data.setCommonCode($p, codeOptions);
};

//-------------------------------------------------------------------------
// 화면로딩시 UDC 호출
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
  $c.gus.cfDisableObjects($p, [ed_clntNo_rslts, txt_clntNm_rslts]);
};

//-------------------------------------------------------------------------
// 조회조기 필드 Clear
//-------------------------------------------------------------------------
scwin.btn_fieldClear_onclick = function (e) {
  $c.gus.cfInitObjects($p, tbl_cndArea, []);
};

//-------------------------------------------------------------------------
// function name : f_Retrieve
// function desc : 조회
//-------------------------------------------------------------------------
scwin.btn_retrieve_onclick = function (e) {
  ds_results.removeAll();
  ds_incidentalExpenses.removeAll();
  $c.sbm.execute($p, sbm_retrieve);
};
scwin.sbm_retrieve_submitdone = function (e) {
  if (e.responseJSON.resultDataSet[0].Code == 0) {
    totalRowsResults.setValue(ds_results.getRowCount());
    if (ds_results.getRowCount() == 0) {
      $c.gus.cfAlertMsg($p, MSG_CM_WRN_002);
      return false;
    } else {
      $c.gus.cfDisableObjects($p, [btn_clntNo_rslts]);
      gr_results.setFocusedCell(0, 0);
      ds_results.setRowPosition(0);
    }
  }
};
scwin.sbm_retrieve_submit = function (e) {
  dma_condition.set("clntNo", ed_clntNo.getValue());
  dma_condition.set("vehclNo", vehclNo.getValue());
  dma_condition.set("bizTypCd", acb_lux_cond_bizTypCd.getValue());
};

//-------------------------------------------------------------------------
// function name : f_retrieve_incExpense
// function desc : 용차료 및 부대비용 정보
//-------------------------------------------------------------------------
scwin.f_retrieve_incExpense = function () {
  dma_cond_incidentalExpenses.set("eqCd", ds_results.getCellData(ds_results.getRowPosition(), "eqCd"));
  $c.sbm.execute($p, sbm_retrieve_incExpense);
};
scwin.sbm_retrieve_incExpense_submitdone = function (e) {
  if (e.responseJSON.resultDataSet[0].Code == 0) {
    totalRows.setValue(gr_incidentalExpenses.getRowCount());
    if (ds_incidentalExpenses.getRowCount() > 0) {
      ds_incidentalExpenses.setRowPosition(0);
      gr_incidentalExpenses.setFocusedCell(0, 0);
    }
  }
};

//-------------------------------------------------------------------------
// function name : f_Save
// function desc : 저장
//-------------------------------------------------------------------------
scwin.btn_save_onclick = async function () {
  for (var i = 0; i < ds_incidentalExpenses.getRowCount(); i++) {
    if (ds_incidentalExpenses.getRowStatus(i) == "C" || ds_incidentalExpenses.getRowStatus(i) == "D" || ds_incidentalExpenses.getRowStatus(i) == "U") {
      if (ds_incidentalExpenses.getCellData(i, "adptYm") == "" && ds_incidentalExpenses.getCellData(i, "adptStDt") == "") {
        $c.win.alert($p, i + 1 + "번재 행의 적용년월 또는 적용기간은 필수 입력 항목 입니다.");
        return false;
      }
      if (ds_incidentalExpenses.getCellData(i, "adptYm") == "" && (ds_incidentalExpenses.getCellData(i, "adptStDt") == "" || ds_incidentalExpenses.getCellData(i, "adptEndDt") == "")) {
        $c.win.alert($p, i + 1 + "번재 행의  적용기간의 FROM,TO는  필수 입력 항목 입니다.");
        return false;
      }
      if (ds_incidentalExpenses.getCellData(i, "clntNo") == "") {
        $c.win.alert($p, i + 1 + "번째 행의 거래처 정보를 등록해 주십시오.");
        return false;
      }
      if (ds_incidentalExpenses.getCellData(i, "selpchItemCd") == "") {
        $c.win.alert($p, i + 1 + "번째 행의 청구/정산 정보를 등록해 주십시오.");
        return false;
      }
      if (ds_incidentalExpenses.getCellData(i, "amtWcrc") == "") {
        $c.win.alert($p, i + 1 + "번째 행의 금액을 등록해 주십시오.");
        return false;
      }
      if (ds_incidentalExpenses.getCellData(i, "deductYn") == 1) {
        if (ds_incidentalExpenses.getCellData(i, "adptDeg") == "") {
          $c.win.alert($p, i + 1 + "번째 행의 적용차수을 등록해 주십시오.");
          return false;
        }
        if (ds_incidentalExpenses.getCellData(i, "allDeg") == "") {
          $c.win.alert($p, i + 1 + "번째 행의 전체차수을 등록해 주십시오.");
          return false;
        }
        if (ds_incidentalExpenses.getCellData(i, "adptTerm") == "") {
          $c.win.alert($p, i + 1 + "번째 행의 적용기간을 등록해 주십시오.");
          return false;
        }
      }
    }
  }
  let confirm = await $c.win.confirm($p, MSG_CM_CRM_001);
  if (confirm) {
    $c.sbm.execute($p, sbm_save);
  }
};
scwin.sbm_save_submitdone = function (e) {
  if (e.responseJSON.resultDataSet[0].Code == 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_INF_001); // 성공적으로 저장하였습니다
    scwin.btn_retrieve_onclick();
  }
};

//-------------------------------------------------------------------------
// 행복사 버튼 기능
//-------------------------------------------------------------------------
scwin.btn_copy_onclick = function (e) {
  if (ds_incidentalExpenses.getRowCount() == 0) {
    return false;
  } else {
    var curRow = ds_incidentalExpenses.getRowPosition(); // 현재 포커스된 행 번호
    var rowData = ds_incidentalExpenses.getRowJSON(curRow); // 현재 행의 데이터를 JSON 형태로 추출
    var newRow = ds_incidentalExpenses.insertRow(ds_incidentalExpenses.getRowCount()); // 맨 끝에 빈 행 추가
    let rowIndex = ds_incidentalExpenses.getRowCount() - 1;
    gr_incidentalExpenses.setFocusedCell(rowIndex, 0);
    ds_incidentalExpenses.setRowJSON(newRow, rowData, true); // 추출한 데이터를 새 행에 붙여넣기
    totalRows.setValue(ds_incidentalExpenses.getRowCount());
  }
};

//-------------------------------------------------------------------------
// 행추가 버튼 기능
//-------------------------------------------------------------------------
scwin.rowAddFunction = function () {
  if (ds_results.getRowCount() == 0) {
    return false;
  }
  ds_incidentalExpenses.insertRow();
  let rowIndex = ds_incidentalExpenses.getRowCount() - 1;
  gr_incidentalExpenses.setFocusedCell(rowIndex, 0);
  ds_incidentalExpenses.setCellData(ds_incidentalExpenses.getRowPosition(), "eqCd", ds_results.getCellData(ds_results.getRowPosition(), "eqCd"));
  ds_incidentalExpenses.setCellData(ds_incidentalExpenses.getRowPosition(), "selpchClsCd", "2");
  ds_incidentalExpenses.setCellData(ds_incidentalExpenses.getRowPosition(), "deductYn", "0");
  ds_incidentalExpenses.setCellData(ds_incidentalExpenses.getRowPosition(), "amtWcrc", 0);
  ds_incidentalExpenses.setCellData(ds_incidentalExpenses.getRowPosition(), "adptDeg", 0);
  ds_incidentalExpenses.setCellData(ds_incidentalExpenses.getRowPosition(), "allDeg", 0);
  ds_incidentalExpenses.setCellData(ds_incidentalExpenses.getRowPosition(), "adptTerm", 0);
  totalRows.setValue(ds_incidentalExpenses.getRowCount());
};

//-------------------------------------------------------------------------
// 행삭제 버튼 기능
//-------------------------------------------------------------------------
scwin.rowDelFunction = function () {
  row = gr_incidentalExpenses.getFocusedRowIndex();
  if (ds_incidentalExpenses.getRowStatus(row) == "C") {
    ds_incidentalExpenses.removeRow(row);
    totalRows.setValue(ds_incidentalExpenses.getRowCount());
    return;
  }
  ds_incidentalExpenses.setCellData(row, "chk", "1");
  ds_incidentalExpenses.modifyRowStatus(row, "D");
  totalRows.setValue(ds_incidentalExpenses.getRowCount());
};

//-------------------------------------------------------------------------
// 취소 버튼 기능
//-------------------------------------------------------------------------
scwin.cancelFunction = function () {
  row = gr_incidentalExpenses.getFocusedRowIndex();
  if (ds_incidentalExpenses.getRowStatus(row) == "C") {
    ds_incidentalExpenses.removeRow(row);
    totalRows.setValue(ds_incidentalExpenses.getRowCount());
    return;
  }
  ds_incidentalExpenses.undoRow(gr_incidentalExpenses.getFocusedRowIndex());
  gr_incidentalExpenses.setFocusedCell(0, 0);
  totalRows.setValue(ds_incidentalExpenses.getRowCount());
};
scwin.gr_results_oncellindexchange = function (rowIndex, columnIndex, oldRow, oldColumnIndex) {
  scwin.f_retrieve_incExpense();
};
scwin.gr_incidentalExpenses_oncellindexchange = async function (row, columnIndex, oldRow, oldColumnIndex) {
  //운송비조회
  var colid = gr_incidentalExpenses.getColumnID(columnIndex);
  if (colid == "deductYn") {
    scwin.gubunFlag = true;
    dsResultsRow = ds_results.getRowPosition();
    if (ds_incidentalExpenses.getCellData(row, "selpchClsCd") == "1") {
      ds_cond_trfAmt.set("clntNo", ds_incidentalExpenses.getCellData(row, "clntNo"));
    } else {
      ds_cond_trfAmt.set("clntNo", ds_results.getCellData(dsResultsRow, "clntNo"));
    }
    ds_cond_trfAmt.set("bizTypCd", ds_results.getCellData(dsResultsRow, "bizTypCd"));
    ds_cond_trfAmt.set("ton", ds_results.getCellData(dsResultsRow, "ton"));
    ds_cond_trfAmt.set("chkClntNo", ds_incidentalExpenses.getCellData(row, "clntNo"));
    ds_cond_trfAmt.set("eqCd", ds_results.getCellData(dsResultsRow, "eqCd"));
    ds_cond_trfAmt.set("selpchClsCd", ds_incidentalExpenses.getCellData(row, "selpchClsCd"));
    await $c.sbm.execute($p, sbm_retrieve_trfAmt);
  }
};
