// selpchItemCd 항목코드
scwin.gr_incidentalExpenses_ontextimageclick = function (rowIndex, columnIndex) {
  let colid = gr_incidentalExpenses.getColumnID(columnIndex);
  if (colid == "clntNo") {
    // clntNo 거래처코드
    let clntNo = ds_incidentalExpenses.getCellData(rowIndex, "clntNo");
    scwin.f_openCommonPopUp(1, clntNo, "");
  }
  if (colid == "selpchItemCd") {
    // selpchItemCd 항목코드
    let selpchItemCd = ds_incidentalExpenses.getCellData(rowIndex, "selpchItemCd");
    scwin.f_openCommonPopUp(2, selpchItemCd, "");
  }
};
scwin.gr_incidentalExpenses_onafteredit = async function (row, columnIndex, value) {
  var colid = gr_incidentalExpenses.getColumnID(columnIndex);
  if (colid == "clntNo") {
    var clntNo = ds_incidentalExpenses.getCellData(row, "clntNo");
    if (clntNo == "") {
      ds_incidentalExpenses.setCellData(row, "clntNo", "");
      return false;
    }
    scwin.f_openCommonPopUp(1, clntNo, "");
  }
  if (colid == "selpchItemCd") {
    var selpchItemCd = ds_incidentalExpenses.getCellData(row, "selpchItemCd");
    if (selpchItemCd == "") {
      ds_incidentalExpenses.setCellData(row, "selpchItemCd", "");
      return false;
    }
    scwin.f_openCommonPopUp(2, selpchItemCd, "");
  }
  if (colid == "selpchClsCd") {
    var dsResultsRow = ds_results.getRowPosition();
    if (ds_incidentalExpenses.getCellData(row, "selpchClsCd") == "1") {
      ds_cond_trfAmt.set("clntNo", ds_incidentalExpenses.getCellData(row, "clntNo"));
    } else {
      ds_cond_trfAmt.set("clntNo", ds_results.getCellData(dsResultsRow, "clntNo"));
    }
    ds_cond_trfAmt.set("bizTypCd", ds_results.getCellData(dsResultsRow, "bizTypCd"));
    ds_cond_trfAmt.set("ton", ds_results.getCellData(dsResultsRow, "ton"));
    ds_cond_trfAmt.set("chkClntNo", ds_incidentalExpenses.getCellData(row, "clntNo"));
    ds_cond_trfAmt.set("eqCd", ds_results.getCellData(dsResultsRow, "eqCd"));
    ds_cond_trfAmt.set("selpchClsCd", ds_incidentalExpenses.getCellData(row, "selpchClsCd"));
    await $c.sbm.execute($p, sbm_retrieve_trfAmt);
  }
};
scwin.sbm_retrieve_trfAmt_submitdone = function (e) {
  if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
    var rRow = ds_results.getRowPosition(); // 차량List
    var iRow = ds_incidentalExpenses.getRowPosition(); // 용차료 및 부대비용 정보

    if (scwin.gubunFlag) {
      scwin.gubunFlag = false;
      if (ds_incidentalExpenses.getCellData(iRow, "selpchItemCd") == "1039") {
        //운송임
        if (ds_trfAmt.getCellData(0, "adptDt") == "") {
          $c.win.alert($p, "조회된 계약요율이 없습니다.");
          return false;
        } else {
          if (ds_incidentalExpenses.getCellData(iRow, "selpchClsCd") == "1") {
            //매출
            ds_incidentalExpenses.setCellData(iRow, "amtWcrc", ds_trfAmt.getCellData(0, "sellAmt"));
          } else if (ds_incidentalExpenses.getCellData(iRow, "selpchClsCd") == "2") {
            //매입
            if (ds_results.getCellData(rRow, "trfAdptCd") == "01" || ds_results.getCellData(rRow, "trfAdptCd") == "03") {
              //장축
              ds_incidentalExpenses.setCellData(iRow, "amtWcrc", ds_trfAmt.getCellData(0, "pchsLongAmt"));
            } else if (ds_results.getCellData(rRow, "trfAdptCd") == "02") {
              ds_incidentalExpenses.setCellData(iRow, "amtWcrc", ds_trfAmt.getCellData(0, "pchsSuperLongAmt"));
            }
          }
          ds_incidentalExpenses.setCellData(iRow, "deductYn", "0"); //공제여부 - no
        }
      }
    } else {
      if (ds_trfAmt.getCellData(0, "chkClntNoExistYn") == "NO" && ds_incidentalExpenses.getCellData(iRow, "clntNo") != "999910") {
        var selpchClsNm = "";
        if (ds_incidentalExpenses.getCellData(iRow, "selpchClsCd") == "1") {
          selpchClsNm = "청구";
        } else if (ds_incidentalExpenses.getCellData(iRow, "selpchClsCd") == "2") {
          selpchClsNm = "정산";
        }
        $c.win.alert($p, "거래처 " + ds_incidentalExpenses.getCellData(iRow, "clntNm") + "는(은) " + ds_results.getCellData(rRow, "vehclNo") + " 차량의 " + selpchClsNm + "거래처로 등록되지 않았습니다. " + "차량관리의 거래처별소속차량관리 화면에서 " + selpchClsNm + "거래처로 등록해 주시기 바랍니다." + "공통거래처(999910)은 제약없이 입력 가능합니다.");
        return false;
      }
      if (ds_incidentalExpenses.getCellData(iRow, "selpchItemCd") == "1039") {
        //운송임
        if (ds_trfAmt.getCellData(0, "adptDt") == "") {
          $c.win.alert($p, "조회된 계약요율이 없습니다.");
          return false;
        } else {
          if (ds_incidentalExpenses.getCellData(iRow, "selpchClsCd") == "1") {
            //매출
            ds_incidentalExpenses.setCellData(iRow, "amtWcrc", ds_trfAmt.getCellData(0, "sellAmt"));
          } else if (ds_incidentalExpenses.getCellData(iRow, "selpchClsCd") == "2") {
            //매입
            if (ds_results.getCellData(rRow, "trfAdptCd") == "01" || ds_results.getCellData(rRow, "trfAdptCd") == "03") {
              //장축
              ds_incidentalExpenses.setCellData(iRow, "amtWcrc", ds_trfAmt.getCellData(0, "pchsLongAmt"));
            } else if (ds_results.getCellData(rRow, "trfAdptCd") == "02") {
              ds_incidentalExpenses.setCellData(iRow, "amtWcrc", ds_trfAmt.getCellData(0, "pchsSuperLongAmt"));
            }
          }
          ds_incidentalExpenses.setCellData(iRow, "deductYn", "0"); //공제여부 - no
        }
      }
    }
  }
};

